import React, { useState, useRef, useEffect } from 'react'

export const BackgroundMusic: React.FC = () => {
  const [isPlaying, setIsPlaying] = useState(false)
  const [showControls, setShowControls] = useState(false)
  const [currentVolume, setCurrentVolume] = useState(0.3)
  const [hasStarted, setHasStarted] = useState(false)
  const [userPaused, setUserPaused] = useState(false)  // ← TRACK USER PAUSE
  const audioRef = useRef<HTMLAudioElement | null>(null)

  useEffect(() => {
    const audio = new Audio('/music/background.mp3')
    audio.loop = true
    audio.volume = 0.3
    audioRef.current = audio

    // Try to auto-play
    audio.play()
      .then(() => {
        setIsPlaying(true)
        setHasStarted(true)
        setUserPaused(false)
        console.log('🎵 Music playing automatically!')
      })
      .catch(() => {
        console.log('🔇 Autoplay blocked - will start on user click')
        setIsPlaying(false)
        setHasStarted(false)
        setUserPaused(false)
      })

    // Start music on any click if not started AND not paused by user
    const startMusicOnClick = () => {
      // Only start if not started AND user didn't manually pause
      if (!hasStarted && !userPaused && audioRef.current) {
        audioRef.current.play()
          .then(() => {
            setIsPlaying(true)
            setHasStarted(true)
            console.log('🎵 Music started on user interaction')
          })
          .catch(err => console.log('Play error:', err))
      }
    }

    document.addEventListener('click', startMusicOnClick)
    document.addEventListener('touchstart', startMusicOnClick)

    return () => {
      audio.pause()
      audio.src = ''
      document.removeEventListener('click', startMusicOnClick)
      document.removeEventListener('touchstart', startMusicOnClick)
    }
  }, [hasStarted, userPaused])  // ← Add dependencies

  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) {
        // User is pausing
        audioRef.current.pause()
        setIsPlaying(false)
        setUserPaused(true)  // ← Mark that user paused
        setHasStarted(true)  // ← Mark as started so it doesn't auto-start again
        console.log('⏸️ User paused music')
      } else {
        // User is playing
        audioRef.current.play()
          .then(() => {
            setIsPlaying(true)
            setUserPaused(false)  // ← User is playing, remove pause flag
            setHasStarted(true)
            console.log('▶️ User resumed music')
          })
          .catch(err => console.log('Play error:', err))
      }
    }
  }

  const handleVolumeChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newVolume = parseFloat(e.target.value)
    setCurrentVolume(newVolume)
    if (audioRef.current) {
      audioRef.current.volume = newVolume
    }
  }

  return (
    <div
      style={{
        position: 'fixed',
        bottom: '20px',
        right: '20px',
        zIndex: 9999,
      }}
      onMouseEnter={() => setShowControls(true)}
      onMouseLeave={() => setShowControls(false)}
    >
      <div
        style={{
          background: 'rgba(10,10,10,0.85)',
          border: '1px solid #c8a20040',
          borderRadius: '12px',
          padding: showControls ? '12px 16px' : '10px',
          backdropFilter: 'blur(10px)',
          transition: 'all 0.3s ease',
          boxShadow: '0 4px 20px rgba(0,0,0,0.5)',
          minWidth: showControls ? '200px' : 'auto',
          display: 'flex',
          alignItems: 'center',
          gap: '10px'
        }}
      >
        <button
          onClick={togglePlay}
          style={{
            background: isPlaying ? '#c8a20020' : '#c8a200',
            border: 'none',
            borderRadius: '50%',
            width: '36px',
            height: '36px',
            cursor: 'pointer',
            fontSize: '18px',
            color: isPlaying ? '#c8a200' : '#0a0a0a',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            transition: 'all 0.3s',
            flexShrink: 0
          }}
        >
          {isPlaying ? '⏸' : '▶️'}
        </button>

        {showControls && (
          <>
            <div style={{ flex: 1 }}>
              <div style={{ 
                fontSize: '10px', 
                color: '#888', 
                marginBottom: '2px',
                whiteSpace: 'nowrap'
              }}>
                🎵 Background Music
              </div>
              <input
                type="range"
                min="0"
                max="1"
                step="0.01"
                value={currentVolume}
                onChange={handleVolumeChange}
                style={{
                  width: '100%',
                  height: '4px',
                  background: 'linear-gradient(to right, #c8a200, #FFD700)',
                  borderRadius: '2px',
                  outline: 'none',
                  cursor: 'pointer',
                  WebkitAppearance: 'none'
                }}
              />
            </div>
            <span style={{ color: '#666', fontSize: '10px' }}>
              {Math.round(currentVolume * 100)}%
            </span>
          </>
        )}
      </div>
    </div>
  )
}
